WITH -- terd의 갯수와 performance_cnt 계산 terd_counts AS ( SELECT doc_no, write_year, doc_type, COUNT(*) AS detail_cnt, SUM(CASE WHEN result_yn IS NOT NULL AND result_yn != '' THEN 1 ELSE 0 END) AS performance_cnt FROM esg.tb_evaluation_report_detail GROUP BY doc_no, write_year, doc_type ),
taiw1_filtered AS ( SELECT * FROM ( SELECT *, ROW_NUMBER() OVER (PARTITION BY target_type, target_id, param ORDER BY updated_at DESC NULLS LAST, created_at DESC) rn FROM esg.tb_approval_info WHERE target_type = 'ER' AND param = 'writer' ) sub WHERE rn = 1 ), tair1_filtered AS ( SELECT * FROM ( SELECT *, ROW_NUMBER() OVER (PARTITION BY target_type, target_id, param ORDER BY updated_at DESC NULLS LAST, created_at DESC) rn FROM esg.tb_approval_info WHERE target_type = 'ER' AND param = 'reviewer' ) sub WHERE rn = 1 ), taia1_filtered AS ( SELECT * FROM ( SELECT *, ROW_NUMBER() OVER (PARTITION BY target_type, target_id, param ORDER BY updated_at DESC NULLS LAST, created_at DESC) rn FROM esg.tb_approval_info WHERE target_type = 'ER' AND param = 'approver' ) sub WHERE rn = 1 ),
taiw3_filtered AS ( SELECT * FROM ( SELECT *, ROW_NUMBER() OVER (PARTITION BY target_type, target_id, param ORDER BY updated_at DESC NULLS LAST, created_at DESC) rn FROM esg.tb_approval_info WHERE target_type = 'ERP' AND param = 'writer' ) sub WHERE rn = 1 ), tair3_filtered AS ( SELECT * FROM ( SELECT *, ROW_NUMBER() OVER (PARTITION BY target_type, target_id, param ORDER BY updated_at DESC NULLS LAST, created_at DESC) rn FROM esg.tb_approval_info WHERE target_type = 'ERP' AND param = 'reviewer' ) sub WHERE rn = 1 ), taia3_filtered AS ( SELECT * FROM ( SELECT *, ROW_NUMBER() OVER (PARTITION BY target_type, target_id, param ORDER BY updated_at DESC NULLS LAST, created_at DESC) rn FROM esg.tb_approval_info WHERE target_type = 'ERP' AND param = 'approver' ) sub WHERE rn = 1 ) -- 본문 쿼리 SELECT ter.*, COALESCE(td.detail_cnt, 0) AS detail_cnt, COALESCE(td.performance_cnt, 0) AS performance_cnt, -- 승인 상태 계산: ER CASE WHEN taia1.signature IS NOT NULL THEN 'Y' WHEN tair1.signature IS NOT NULL THEN 'I' WHEN taiw1.signature IS NOT NULL THEN 'W' ELSE 'C' END AS approval_status_r, -- 승인 상태 계산: ERP CASE WHEN taia3.signature IS NOT NULL THEN 'Y' WHEN tair3.signature IS NOT NULL THEN 'I' WHEN taiw3.signature IS NOT NULL THEN 'W' ELSE 'C' END AS approval_status_p FROM esg.tb_evaluation_report ter LEFT JOIN terd_counts td ON td.write_year = ter.write_year AND td.doc_no = ter.doc_no AND td.doc_type = ter.doc_type -- ER JOIN LEFT JOIN taiw1_filtered taiw1 ON taiw1.target_id = td.write_year || td.doc_no LEFT JOIN tair1_filtered tair1 ON tair1.target_id = td.write_year || td.doc_no LEFT JOIN taia1_filtered taia1 ON taia1.target_id = td.write_year || td.doc_no -- ERP JOIN LEFT JOIN taiw3_filtered taiw3 ON taiw3.target_id = td.write_year || td.doc_no LEFT JOIN tair3_filtered tair3 ON tair3.target_id = td.write_year || td.doc_no LEFT JOIN taia3_filtered taia3 ON taia3.target_id = td.write_year || td.doc_no WHERE 1 = 1 AND ter.comp_id = #{compId} AND ter.write_year = #{writeYear}
AND ter.doc_no = #{docNo}
ORDER BY evaluation_dt DESC, ter.use_yn DESC, ter.doc_no DESC

