UPDATE esg.tb_evaluation_report
   SET
      evaluation_dt = #{evaluationDt},
      evaluation_target = #{evaluationTarget},
      use_yn = #{useYn},
      updated_at = now(),
      updated_by = #{updatedBy}
WHERE comp_id = #{compId}
  AND write_year = #{writeYear}
  AND doc_no = #{docNo}
  AND doc_type = #{docType}

