SELECT tlce.*, esg.fn_getapprovalstatus(#{docType}, tlce.write_year || tlce.doc_no) as approval_status, COUNT(tlced.doc_seq) as complianceCnt, COUNT(CASE WHEN tlced.legal_review_yn = 'N' AND tlced.use_yn = 'Y' THEN 1 END) as legalReviewNotCompliedCnt, COUNT(CASE WHEN tlced.legal_review_yn IS NULL AND tlced.use_yn = 'Y' THEN 1 END) as legalReviewNotEvaluatedCnt FROM esg.tb_legal_comlpliance_evaluation tlce LEFT JOIN esg.tb_legal_comlpliance_evaluation_detail tlced ON tlce.write_year = tlced.write_year AND tlce.doc_type = tlced.doc_type AND tlce.doc_no = tlced.doc_no WHERE tlce.write_year = #{writeYear} AND tlce.doc_type = #{docType} AND tlce.comp_id = #{compId}
AND tlce.doc_no = #{docNo}
GROUP BY tlce.write_year, tlce.doc_type, tlce.doc_no, tlce.comp_id ORDER BY tlce.doc_no DESC

SELECT tlced.*, tlm.legal_nm, tlmd.article_title AS legal_article_nm, tlr.legal_review_nm, sf.file_id, sf.file_nm, -- 파일 이름 가져오기 sf.file_size -- 파일 크기 가져오기 FROM esg.tb_legal_comlpliance_evaluation tlce LEFT JOIN esg.tb_legal_comlpliance_evaluation_detail tlced ON tlced.doc_type = tlce.doc_type AND tlced.doc_no = tlce.doc_no AND tlced.write_year = tlce.write_year LEFT JOIN esg.tb_sys_file sf ON sf.target_id = tlced.write_year || tlced.doc_no || tlced.doc_seq AND sf.target_type = 'LCE' LEFT JOIN esg.tb_legal_review_detail tlrd ON tlrd.write_year = tlced.review_write_year AND tlrd.doc_no = tlced.review_doc_no AND tlrd.doc_seq = tlced.review_doc_seq LEFT JOIN esg.tb_legal_review tlr ON tlr.write_year = tlrd.write_year AND tlr.doc_no = tlrd.doc_no AND tlr.comp_id = #{compId} LEFT JOIN esg.tb_legal_manage_detail tlmd ON tlmd.write_year = tlrd.legal_write_year AND tlmd.doc_no = tlrd.legal_doc_no AND tlmd.doc_seq = tlrd.legal_doc_seq LEFT JOIN esg.tb_legal_manage tlm ON tlm.write_year = tlmd.write_year AND tlm.doc_no = tlmd.doc_no AND tlm.comp_id = #{compId} WHERE 1 = 1 AND tlce.write_year = #{writeYear} AND tlce.doc_type = #{docType} AND tlce.comp_id = #{compId} AND tlce.doc_no = #{docNo} AND tlced.doc_no IS NOT NULL
AND tlced.doc_seq = #{docSeq}
ORDER BY CAST(tlced.doc_seq AS INTEGER) ASC

SELECT tlcedo.*
  FROM esg.tb_legal_comlpliance_evaluation_detail_orgn tlcedo
  LEFT JOIN esg.tb_legal_comlpliance_evaluation_detail tlced
    ON tlcedo.doc_type = tlced.doc_type
   AND tlcedo.doc_no = tlced.doc_no
   AND tlcedo.write_year = tlced.write_year
   AND tlced.doc_seq = #{docSeq}
WHERE 1 = 1
  AND tlcedo.write_year = #{writeYear}
  AND tlcedo.doc_type = #{docType}
  AND tlcedo.doc_no = #{docNo}
  AND tlcedo.doc_seq = #{docSeq}
ORDER BY tlcedo.doc_seq DESC

